const { EventEmitter } = require('node:events');
const { createProxyMiddleware } = require('/workspace/http-proxy-middleware/dist');

async function invoke(middleware, req) {
  let nextCalls = 0;
  await middleware(req, {}, () => {
    nextCalls += 1;
  });
  if (nextCalls !== 1) {
    throw new Error(`Expected next() once, received ${nextCalls}`);
  }
}

async function main() {
  const middleware = createProxyMiddleware({
    pathFilter: '/proxy',
    target: 'http://localhost:65535',
    ws: true,
  });

  await invoke(middleware, {
    method: 'GET',
    url: '/not-proxied',
    headers: {},
    socket: { server: null },
  });

  await invoke(middleware, {
    method: 'GET',
    url: '/not-proxied',
    headers: {},
  });

  const server = new EventEmitter();
  await invoke(middleware, {
    method: 'GET',
    url: '/not-proxied',
    headers: {},
    socket: { server },
  });
  await invoke(middleware, {
    method: 'GET',
    url: '/not-proxied',
    headers: {},
    socket: { server },
  });

  if (server.listenerCount('upgrade') !== 1) {
    throw new Error(`Expected one upgrade listener, found ${server.listenerCount('upgrade')}`);
  }

  console.log('websocket upgrade subscription handles null, missing, and duplicate server cases');
}

main().catch((err) => {
  console.error(`${err.name}: ${err.message}`);
  console.error(err.stack.split('\n').slice(0, 4).join('\n'));
  process.exitCode = 1;
});
EOF
